INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2f84a228-9272-442d-82aa-cbf85d7f9247',
  '00000000-0000-0000-0000-000000000001',
  $escape$Optimism EVM: Mastering Gas & Fees with EIP-1559$escape$,
  $escape$When sending transactions on Optimism EVM, you need to consider gas and fees. EIP-1559 introduced base fee and priority fee, replacing the traditional gas price. The base fee is the minimum amount required to include your transaction in the next block, while the priority fee is an additional fee that determines the order of transactions. To optimize gas usage, use the `gasLimit` property in your transaction object. You can also use the `maxFeePerGas` and `maxPriorityFeePerGas` properties to control the base and priority fees, respectively.$escape$,
  $escape$const tx = {
  to: '0x...,
  gasLimit: 80000,
  maxFeePerGas: 20000000000,
  maxPriorityFeePerGas: 10000000000,
};
 optimismProvider.sendTransaction(tx).then((txHash) => console.log(txHash));$escape$,
  $escape$javascript$escape$,
