INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '21bd7daf-23aa-46e0-996b-53a688cc19a4',
  '00000000-0000-0000-0000-000000000001',
  $escape$Optimism Bridges — Locking, Minting, and Risk Mitigation$escape$,
  $escape$When building a bridge on Optimism, you must choose between a canonical bridge and a third-party bridge. A canonical bridge is a pre-approved bridge that has been vetted by Optimism, whereas a third-party bridge requires manual approval. Canonical bridges use the `Locking` function to lock funds in an Optimism account, whereas third-party bridges use the `Mint` function to create a new token on Optimism. However, third-party bridges come with increased risk, as they are not officially supported by Optimism.$escape$,
  $escape$const Locking = require('@optimism/locking');
const Mint = require('@optimism/mint');
// Canonical bridge using Locking
Locking.lockFunds(
    { chainId: 1, account: '0x...' },
    { value: '1.0 ether' }
);
// Third-party bridge using Mint
Mint.createToken(
    { chainId: 1, account: '0x...' },
    { name: 'BridgeToken', symbol: 'BRIDGE' }
)$escape$,
